const update = $json;
let chatId, text = '';
let raw = update;
let callbackQueryId = null;
let callbackMessageId = null;
let isCallback = false;

if (update.message) {
  chatId = update.message.chat.id;
  text = update.message.text || '';
} else if (update.callback_query) {
  isCallback = true;
  callbackQueryId = update.callback_query.id;
  chatId = update.callback_query.message.chat.id;
  callbackMessageId = update.callback_query.message.message_id;
  text = update.callback_query.data || '';
}

return [{ json: { chatId, text, raw, isCallback, callbackQueryId, callbackMessageId } }];

const data = $getWorkflowStaticData('global');
const catalog = data.catalog;
const vendedores = data.vendedores;
const incomingText = String($json?.text || '').trim();
const isReloadCommand = incomingText === '/reload';
let memoryEmpty = true;

if (catalog && Object.keys(catalog).length > 0) {
  let hasOptions = false;
  for (const model of Object.values(catalog)) {
    if (!model || !Array.isArray(model.steps)) continue;
    for (const step of model.steps) {
      if (!step || !Array.isArray(step.options)) continue;
      if (step.options.length > 0) { hasOptions = true; break; }
    }
    if (hasOptions) break;
  }
  memoryEmpty = !hasOptions;
}

if (!memoryEmpty && (!vendedores || Object.keys(vendedores).length === 0)) {
  memoryEmpty = true;
}

if (isReloadCommand) memoryEmpty = true;

const firstItem = $input.first()?.json ?? {};
return [{ json: { ...firstItem, memoryEmpty, shouldReload: isReloadCommand, isReloadCommand } }];

const toNum = (v) => {
  if (v === null || v === undefined) return 0;
  const s = String(v).replace(/[^0-9.\-]/g, '');
  const n = parseFloat(s);
  return Number.isFinite(n) ? n : 0;
};
const toInt = (v, d=0) => {
  const n = parseInt(String(v), 10);
  return Number.isFinite(n) ? n : d;
};
const normKey = (k) => String(k || '').toLowerCase().trim().replace(/\s+/g,'').replace(/[_\-]/g,'');
const getVal = (obj, terms) => {
  if (!obj) return undefined;
  const keys = Object.keys(obj);
  const map = new Map(keys.map(k => [normKey(k), k]));
  for (const t of terms) {
    const nk = normKey(t);
    if (map.has(nk)) return obj[map.get(nk)];
  }
  for (const t of terms) {
    const nk = normKey(t);
    const partial = keys.find(k => normKey(k).includes(nk));
    if (partial) return obj[partial];
  }
  return undefined;
};
const norm = (v) => String(v ?? '').trim().replace(/\s+/g, ' ');
const normLower = (v) => norm(v).toLowerCase();
const optionSeen = new WeakMap();
const maquinasRows = $items('Leer DB_Maquinas').map(i => i.json);
const opcionesRows = $items('Leer DB_Opciones').map(i => i.json);
const preciosRows = $items('Leer DB_Precios').map(i => i.json);
const catalog = {};
const priceLookup = new Map();
const basePriceOptionsByModel = new Map();
const priceKey = (modelo, paso, opcion) => `${normLower(modelo)}||${normLower(paso)}||${normLower(opcion)}`;
const isBaseStep = (s) => {
  const x = normLower(s);
  return !x || ['base','baseprice','precio_base','preciobase','pricebase','base_price'].includes(x);
};

for (const row of preciosRows) {
  const modelo = getVal(row, ['modelo','model','maquina','maquina_id']);
  const pasoId = getVal(row, ['paso_id','step_id','paso','step']);
  const opcion = getVal(row, ['opcion','opcion_label','opcion_valor','label','value','nombre_opcion']);
  const precio = toNum(getVal(row, ['precio','price','costo','opcion_precio','extra','precio_extra_usd']));
  if (!modelo || !opcion) continue;
  if (isBaseStep(pasoId)) {
    const modelKey = String(modelo);
    const arr = basePriceOptionsByModel.get(modelKey) || [];
    arr.push({ key: `BP_${arr.length + 1}`, label: String(opcion), price: precio });
    basePriceOptionsByModel.set(modelKey, arr);
    continue;
  }
  priceLookup.set(priceKey(modelo, pasoId, opcion), precio);
}

for (const row of maquinasRows) {
  const modelo = getVal(row, ['modelo','model','id','maquina_id']);
  if (!modelo) continue;
  const nombre = getVal(row, ['nombre','name','descripcion','description']) ?? modelo;
  const basePrice = toNum(getVal(row, ['precio_base','base_price','price','precio','costo']));
  const plantilla = getVal(row, ['plantilla','template','docx','archivo']);
  const modelId = String(modelo);
  const fromSheet = (basePriceOptionsByModel.get(modelId) || []).filter(p => Number.isFinite(p.price));
  const defaultOption = [{ key: 'BASE', label: 'Precio base', price: basePrice }];
  const priceOptions = fromSheet.length > 0 ? fromSheet : defaultOption;
  catalog[modelId] = {
    id: modelId, name: String(nombre), basePrice, priceOptions,
    plantilla: plantilla ? String(plantilla) : undefined, steps: []
  };
}

for (const row of opcionesRows) {
  const modelo = getVal(row, ['modelo','model','maquina','maquina_id']);
  if (!modelo) continue;
  const m = catalog[String(modelo)];
  if (!m) continue;
  const pasoId = getVal(row, ['paso_id','step_id','paso','step']);
  const pregunta = getVal(row, ['pregunta','paso_pregunta','question','texto']);
  const orden = toInt(getVal(row, ['paso_orden','order','orden']), 0);
  if (!pasoId) continue;
  let step = m.steps.find(s => s.id === String(pasoId));
  if (!step) {
    const questionStr = norm(pregunta);
    step = { id: String(pasoId), question: questionStr || 'Selecciona una opción', order: orden, options: [] };
    m.steps.push(step);
  }
  const rawLabel = getVal(row, ['opcion_label','label','etiqueta','nombre_opcion','opcion']) || getVal(row, ['opcion label','opcion_label','opcionlabel']);
  const rawValue = getVal(row, ['opcion_valor','value','valor','code','key']) || rawLabel;
  const fallbackPrice = toNum(getVal(row, ['opcion_precio','price','precio','costo','extra','precio_extra_usd']));
  const labelStr = norm(rawLabel || rawValue);
  let valueStr = norm(rawValue || rawLabel || labelStr);
  if (labelStr === '') continue;
  if (valueStr === '') valueStr = labelStr;
  const modelKey = String(modelo);
  const priceFromSheet = priceLookup.get(priceKey(modelKey, pasoId, valueStr)) ?? priceLookup.get(priceKey(modelKey, pasoId, labelStr));
  const price = Number.isFinite(priceFromSheet) ? priceFromSheet : fallbackPrice;
  const key = `${normLower(labelStr)}|${normLower(valueStr)}`;
  let seenForStep = optionSeen.get(step);
  if (!seenForStep) { seenForStep = new Set(); optionSeen.set(step, seenForStep); }
  if (seenForStep.has(key)) continue;
  seenForStep.add(key);
  step.options.push({ label: labelStr, value: valueStr, price });
}

for (const mid of Object.keys(catalog)) {
  catalog[mid].steps.sort((a,b) => (a.order ?? 0) - (b.order ?? 0));
}

// === FASE 1: Cargar vendedores ===
let vendedoresRows;
try { vendedoresRows = $items('Leer DB_Vendedores').map(i => i.json); } catch(e) { vendedoresRows = []; }
const vendedoresMap = {};
for (const row of vendedoresRows) {
  const usuario = String(row.usuario || '').trim().toLowerCase();
  if (!usuario) continue;
  vendedoresMap[usuario] = {
    usuario: usuario,
    password: String(row.password || ''),
    nombre_completo: String(row.nombre_completo || ''),
    email_vendedor: String(row.email_vendedor || ''),
    rol: String(row.rol || 'vendedor').toLowerCase(),
    activo: String(row.activo || '').toUpperCase() === 'TRUE'
  };
}

const input = $input.first().json;
const staticData = $getWorkflowStaticData('global');
staticData.catalog = catalog;
staticData.vendedores = vendedoresMap;
return [{ json: { ...input, catalogLoaded: true, models: Object.keys(catalog).length, vendedoresLoaded: Object.keys(vendedoresMap).length } }];

const { chatId, text, raw, shouldReload: inReload, isCallback, callbackQueryId, callbackMessageId } = $json;
const staticData = $getWorkflowStaticData('global');
staticData.cot = staticData.cot || {};
staticData.sessions = staticData.sessions || {};

const SESSION_DURATION = 8 * 60 * 60 * 1000;
const LOCK_DURATION = 15 * 60 * 1000;
const MAX_ATTEMPTS = 3;
const now = Date.now();

const incomingText = String(text || '').trim();
const isReloadCommand = incomingText === '/reload';
const isLogoutCommand = incomingText === '/logout';
const isStartCommand = incomingText === '/start';

const reportCommands = ['/reporte_mes', '/reporte_anual', '/reporte_detalle', '/reporte_vendedor', '/mis_cotizaciones', '/exportar_excel'];
const isReportCommand = reportCommands.some(cmd => incomingText.startsWith(cmd));

const session = staticData.sessions[chatId];
const isAuthenticated = session && session.loginTimestamp && (now - session.loginTimestamp) < SESSION_DURATION;

const loginState = staticData.cot[chatId];
const isInLoginFlow = loginState && (loginState.stage === 'await_username' || loginState.stage === 'await_password');

let action = null;

if (isReloadCommand) {
  action = 'RELOAD_DONE';
} else if (isLogoutCommand) {
  if (isAuthenticated) {
    delete staticData.sessions[chatId];
    delete staticData.cot[chatId];
  }
  action = 'LOGOUT';
} else if (!isAuthenticated && !isInLoginFlow) {
  const sess = staticData.sessions[chatId] || {};
  if (sess.lockedUntil && now < sess.lockedUntil) {
    action = 'BLOCKED';
  } else {
    if (sess.lockedUntil && now >= sess.lockedUntil) {
      sess.failedAttempts = 0;
      sess.lockedUntil = null;
      staticData.sessions[chatId] = sess;
    }
    staticData.cot[chatId] = { stage: 'await_username' };
    action = 'LOGIN_FLOW';
  }
} else if (isInLoginFlow) {
  action = 'LOGIN_FLOW';
} else if (isAuthenticated) {
  if (isReportCommand) {
    action = 'REPORTES';
  } else if (isStartCommand || (raw?.message?.text && raw.message.text.startsWith('/') && !isReportCommand)) {
    const prevMode = staticData.cot[chatId]?.mode;
    staticData.cot[chatId] = { mode: prevMode };
    action = 'START';
  } else if (raw?.callback_query?.data) {
    const data = raw.callback_query.data;
    if (data === 'MENU|AVANZADA' || data === 'MODE|ADV') {
      const current = staticData.cot[chatId] || {};
      staticData.cot[chatId] = { ...current, mode: 'ADV' };
      action = 'MENU_SELECTION';
    } else if (data === 'MODE|FAST') {
      const current = staticData.cot[chatId] || {};
      staticData.cot[chatId] = { ...current, mode: 'FAST' };
      action = 'MENU_SELECTION';
    } else {
      action = 'COTIZACION_FLOW';
    }
  } else if (raw?.message?.text && !raw.message.text.startsWith('/') && staticData.cot[chatId]) {
    action = 'COTIZACION_FLOW';
  } else {
    action = 'START';
  }
}

if (!action) action = 'START';

const outText = action === 'RELOAD_DONE' ? '✅ Catálogo y vendedores actualizados' : text;
return [{ json: { chatId, text: outText, action, shouldReload: !!inReload || isReloadCommand, isReloadCommand, raw, isCallback, callbackQueryId, callbackMessageId, reportCommand: isReportCommand ? incomingText : null } }];

const staticData = $getWorkflowStaticData('global');
const catalog = staticData.catalog || {};
const models = Object.keys(catalog);
if (models.length === 0) {
  return [{ json: { chatId: $json.chatId, text: '⚠️ La memoria está vacía. Por favor ejecuta /start para recargar.', reply_markup: {} } }];
}
const keyboard = [];
let row = [];
models.forEach((model, index) => {
  row.push({ text: model, callback_data: `${model}|START` });
  if (row.length === 2 || index === models.length - 1) { keyboard.push(row); row = []; }
});
return [{ json: { chatId: $json.chatId, text: '🏭 *Catálogo VC999 Disponible*\n\nSelecciona la máquina que deseas cotizar:', reply_markup: { inline_keyboard: keyboard } } }];

const staticData = $getWorkflowStaticData('global');
const catalog = staticData.catalog || {};
staticData.cot = staticData.cot || {};
const chatId = $json.chatId;
const text = String($json.text ?? '').trim();
const callbackMessageId = $json.callbackMessageId ?? null;
const callbackQueryId = $json.callbackQueryId ?? null;
const isCallback = !!$json.isCallback;

const money = (n) => Number(n || 0).toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 0 });
const toNum = (v) => { const s = String(v ?? '').replace(/[^0-9.,\-]/g, '').replace(/,/g, ''); const n = parseFloat(s); return Number.isFinite(n) ? n : 0; };
const normText = (v) => String(v ?? '').trim().replace(/\s+/g, ' ');
const optionKey = (label, value) => `${normText(label).toLowerCase()}|${normText(value ?? label).toLowerCase()}`;
const humanizeStepId = (stepId) => { const safe = String(stepId ?? '').trim(); const ws = safe.replace(/[_-]+/g, ' ').replace(/([a-z])([A-Z])/g, '$1 $2').trim(); if (!ws) return 'Paso'; return ws.split(' ').filter(Boolean).map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join(' '); };
const resolveMode = (state) => (state?.mode || 'ADV').toUpperCase();
const sanitizeMachine = (v) => String(v ?? '').trim().replace(/\.docx$/i, '');
const ensureRunId = (state) => { if (!state.runId) state.runId = `${Date.now()}_${chatId}`; return state.runId; };
const formatSelections = (sel) => Array.isArray(sel) && sel.length > 0 ? sel.map(s => { const sl = humanizeStepId(s.step ?? 'Paso'); const pt = toNum(s.price) > 0 ? ` (+$${money(s.price)} USD)` : ' (+$0 USD)'; return `- ${sl}: ${s.value ?? 'N/A'}${pt}`; }) : ['- Sin opciones'];
const startFastDefaults = (us, machine) => { const steps = Array.isArray(machine.steps) ? machine.steps : []; const sels = []; let tp = toNum(us.basePrice); steps.forEach((step, idx) => { const opts = Array.isArray(step?.options) ? step.options : []; if (opts.length === 0) return; const def = opts.find(o => String(o.label ?? '').includes('(Default)')) || opts[0]; const cp = toNum(def.price); sels.push({ step: step?.id ?? `step_${idx+1}`, value: def.value ?? def.label ?? 'NA', price: cp }); tp += cp; }); us.selections = sels; us.totalPrice = tp; us.stepIndex = steps.length; us.stage = 'await_customer_name'; return { text: '⚡️ *Modo Rápido activado*\nOpciones por defecto seleccionadas. Escribe el *nombre del cliente*.', reply_markup: {} }; };

const session = staticData.sessions?.[chatId] || {};
const editMenuMarkup = { inline_keyboard: [[{ text: '💰 Precio base', callback_data: 'EDIT|BASE_PRICE' }],[{ text: '⚙️ Opciones', callback_data: 'EDIT|OPTIONS' }],[{ text: '👤 Nombre cliente', callback_data: 'EDIT|CUSTOMER_NAME' }],[{ text: '📧 Email cliente', callback_data: 'EDIT|CUSTOMER_EMAIL' }],[{ text: '✅ Listo, regenerar PDF', callback_data: 'EDIT|DONE' }]] };

const output = (p) => [{ json: { ...p, chatId, callbackMessageId, callbackQueryId, isCallback } }];

if (!chatId) return output({ text: '⚠️ Falta chatId.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState: null });

let userState = staticData.cot[chatId] || null;
const isStartMachine = text.includes('|') && text.endsWith('|START');
const isBasePick = text.includes('|BP|');
const isOpt = text.includes('|OPT|');

// === FASE 6: Duplicate callbacks ===
if (isCallback && (text === 'DUP|EDIT' || text === 'DUP|NEW')) {
  if (text === 'DUP|NEW') {
    userState.stage = 'done';
    userState.duplicateAction = 'new';
    const payload = { machine: sanitizeMachine(userState.machine), basePrice: toNum(userState.basePrice), totalPrice: toNum(userState.totalPrice), selections: userState.selections, customer: userState.customer, advisor: session.nombre_completo || 'N/A', runId: ensureRunId(userState) };
    userState.payloadFinal = payload;
    staticData.cot[chatId] = userState;
    const ol = formatSelections(userState.selections).join('\n');
    return output({ text: `🛠️ *Nueva Cotización ${userState.machine}*\n*Base:* $${money(payload.basePrice)} USD\n*Opciones:*\n${ol}\n*Total:* $${money(payload.totalPrice)} USD\n*Cliente:* ${userState.customer.name}\n*Correo:* ${userState.customer.email}\n*Asesor:* ${payload.advisor}\n✅ Generando nueva cotización...`, reply_markup: {}, isFinished: true, isReadyToGenerate: true, quotePayload: payload, userState });
  }
  if (text === 'DUP|EDIT') {
    userState.stage = 'edit_menu';
    userState.editMode = true;
    staticData.cot[chatId] = userState;
    return output({ text: `📋 *Editando:* ${userState.duplicateFolio || 'N/A'}\n*Máquina:* ${userState.machine}\n*Precio base:* $${money(userState.basePrice)} USD\n*Total:* $${money(userState.totalPrice)} USD\n*Cliente:* ${userState.customer.name} (${userState.customer.email})\n\n¿Qué deseas editar?`, reply_markup: editMenuMarkup, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
  }
}

// === Edit mode callbacks ===
if (isCallback && text.startsWith('EDIT|') && userState?.editMode) {
  const ea = text.split('|')[1];
  if (ea === 'BASE_PRICE') { userState.stage = 'edit_base_price'; staticData.cot[chatId] = userState; return output({ text: '💰 Escribe el nuevo *precio base* (ej: 16995):', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState }); }
  if (ea === 'OPTIONS') { userState.stage = 'config'; userState.stepIndex = 0; userState.selections = []; userState.totalPrice = toNum(userState.basePrice); staticData.cot[chatId] = userState; }
  if (ea === 'CUSTOMER_NAME') { userState.stage = 'edit_customer_name'; staticData.cot[chatId] = userState; return output({ text: '👤 Escribe el nuevo *nombre del cliente*:', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState }); }
  if (ea === 'CUSTOMER_EMAIL') { userState.stage = 'edit_customer_email'; staticData.cot[chatId] = userState; return output({ text: '📧 Escribe el nuevo *email del cliente*:', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState }); }
  if (ea === 'DONE') {
    userState.stage = 'done';
    const payload = { machine: sanitizeMachine(userState.machine), basePrice: toNum(userState.basePrice), totalPrice: toNum(userState.totalPrice), selections: userState.selections, customer: userState.customer, advisor: session.nombre_completo || 'N/A', runId: ensureRunId(userState), isEdit: true, editFolio: userState.duplicateFolio, editFileId: userState.duplicateFileId, editRowIndex: userState.duplicateRowIndex, editVersion: (userState.duplicateVersion || 1) + 1 };
    userState.payloadFinal = payload;
    staticData.cot[chatId] = userState;
    const ol = formatSelections(userState.selections).join('\n');
    return output({ text: `🛠️ *Editando ${userState.duplicateFolio}*\n*Base:* $${money(payload.basePrice)} USD\n*Opciones:*\n${ol}\n*Total:* $${money(payload.totalPrice)} USD\n*Cliente:* ${userState.customer.name}\n*Versión:* ${payload.editVersion}\n✅ Regenerando PDF...`, reply_markup: {}, isFinished: true, isReadyToGenerate: true, quotePayload: payload, userState });
  }
}

// === Edit text inputs ===
if (!isCallback && userState?.editMode) {
  const msg = normText(text);
  if (userState.stage === 'edit_base_price') {
    const np = toNum(text); if (np <= 0) return output({ text: '⚠️ Precio inválido.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
    userState.basePrice = np; const st = (userState.selections||[]).reduce((s,x)=>s+toNum(x.price),0); userState.totalPrice = np + st; userState.stage = 'edit_menu'; staticData.cot[chatId] = userState;
    return output({ text: `✅ Precio base: $${money(np)} USD | Total: $${money(userState.totalPrice)} USD\n\n¿Qué más editar?`, reply_markup: editMenuMarkup, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
  }
  if (userState.stage === 'edit_customer_name') { userState.customer.name = msg; userState.stage = 'edit_menu'; staticData.cot[chatId] = userState; return output({ text: `✅ Nombre: ${msg}\n\n¿Qué más editar?`, reply_markup: editMenuMarkup, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState }); }
  if (userState.stage === 'edit_customer_email') { userState.customer.email = msg; userState.stage = 'edit_menu'; staticData.cot[chatId] = userState; return output({ text: `✅ Email: ${msg}\n\n¿Qué más editar?`, reply_markup: editMenuMarkup, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState }); }
}

if (isStartMachine) {
  const model = sanitizeMachine(text.split('|')[0]);
  const machine = catalog[model];
  if (!machine) return output({ text: '⚠️ Máquina no encontrada. Ejecuta /start.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
  const mode = resolveMode(userState);
  const lbp = toNum(machine.basePrice);
  userState = { mode, stage: 'await_base_price_choice', machine: model, stepIndex: 0, selections: [], basePrice: lbp, totalPrice: lbp, customer: {}, advisor: '' };
  ensureRunId(userState);
  staticData.cot[chatId] = userState;
  return output({ text: `Precio base: $${money(lbp)} USD. ¿Deseas cambiarlo?`, reply_markup: { inline_keyboard: [[{ text: `✅ Usar $${money(lbp)}`, callback_data: `${model}|BP|LIST` }],[{ text: '✏️ Cambiar precio', callback_data: `${model}|BP|MANUAL` }]] }, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
}

if (isBasePick) {
  const [rawModel, , action] = text.split('|');
  const model = sanitizeMachine(rawModel);
  const machine = catalog[model];
  if (!userState || !machine || userState.machine !== model) return output({ text: '⚠️ Sesión expirada. Ejecuta /start.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
  if (action === 'MANUAL') { userState.stage = 'await_base_price_manual'; staticData.cot[chatId] = userState; return output({ text: '✏️ Escribe el nuevo *PRECIO BASE* (ej: 16995).', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState }); }
  userState.basePrice = toNum(machine.basePrice); userState.totalPrice = toNum(machine.basePrice); userState.stage = 'config'; staticData.cot[chatId] = userState;
  if (userState.mode === 'FAST') { const fr = startFastDefaults(userState, machine); staticData.cot[chatId] = userState; return output({ ...fr, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState }); }
}

if (isOpt) {
  const [model, , stepId, val, rawPrice] = text.split('|');
  const price = toNum(rawPrice);
  if (!userState || userState.machine !== model) return output({ text: '⚠️ Sesión expirada.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
  if (userState.mode === 'FAST') return output({ text: '⚡️ Modo Rápido. Opciones auto-seleccionadas.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
  userState.selections.push({ step: stepId, value: val, price });
  userState.totalPrice = toNum(userState.totalPrice) + price;
  userState.stepIndex += 1;
  if (userState.editMode) {
    const mc = catalog[userState.machine];
    if (mc && userState.stepIndex >= mc.steps.length) {
      userState.stage = 'edit_menu'; staticData.cot[chatId] = userState;
      return output({ text: `✅ Opciones actualizadas. Total: $${money(userState.totalPrice)} USD\n\n¿Qué más editar?`, reply_markup: editMenuMarkup, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
    }
  }
}

if (!isCallback && userState) {
  const msg = normText(text);
