const toNum = (v) => {
  const s = String(v ?? '').replace(/[^0-9.\-]/g, '');
  const n = parseFloat(s);
  return Number.isFinite(n) ? n : 0;
};

const sanitizeMachine = (v) => String(v ?? '').trim().replace(/\.docx$/i, '');
const machineRaw = userState.machine ?? input.quotePayload?.machine ?? '';
const machine = sanitizeMachine(machineRaw);

