  ? Number(userState.basePrice)
  : Number(input.quotePayload?.basePrice ?? 0);

const selections = Array.isArray(userState.selections)
  ? userState.selections.map(sel => ({
      step: sel.step ?? '',
      value: sel.value ?? '',
      price: toNum(sel.price),
    }))
  : [];

const selectionsTotal = selections.reduce((sum, sel) => sum + toNum(sel.price), 0);

const totalPrice = Number.isFinite(Number(userState.totalPrice))
  ? Number(userState.totalPrice)
  : basePrice + selectionsTotal;

const runId = String(userState.runId ?? input.quotePayload?.runId ?? `${Date.now()}_${input.chatId}`);
const advisor = session.nombre_completo || userState.advisor || '';

// ====== Construir placeholders/reemplazos para el DOCX/PDF ======
const aliasMap = {
  // ES -> EN (por compatibilidad si tu backend/plantilla usa ambos)
  'voltaje': 'voltage',
  'operacion': 'operation',
  'tamano_tapa': 'lid_size',
  'tamaño_tapa': 'lid_size',
  'opcion_bomba': 'pump_options',
  'registro_fotografias': 'photo_log',
  'forma_matriz': 'mold_shape',
  'proceso': 'process',
  'config_matriz': 'matrix_config',
  'tipo_matriz': 'die_type',
};

const steps = Array.isArray(machineObj?.steps) ? machineObj.steps : [];
const stepById = new Map(steps.map(s => [String(s.id ?? ''), s]));

const findLabel = (stepId, val) => {
  const step = stepById.get(String(stepId)) || null;
  const opts = Array.isArray(step?.options) ? step.options : [];
  const v = String(val ?? '');
  const hit = opts.find(o => String(o.value ?? '') === v) || opts.find(o => String(o.label ?? '') === v);
  return hit?.label ? String(hit.label) : v;
};

const keyVariants = (k) => {
  const base = String(k ?? '').trim();
  const lower = base.toLowerCase();
  let noAccent = lower;
  try { noAccent = lower.normalize('NFD').replace(/[\u0300-\u036f]/g, ''); } catch(e) {}
  const snake = noAccent.replace(/[^a-z0-9]+/g, '_').replace(/^_+|_+$/g, '');
  return Array.from(new Set([base, lower, noAccent, snake].filter(Boolean)));
};

const placeholders = {};
const placeholders_raw = {};

const addPlaceholder = (k, labelVal, rawVal) => {
  for (const kv of keyVariants(k)) {
    placeholders[kv] = labelVal || rawVal || '';
    placeholders_raw[kv] = rawVal || '';
  }
};

for (const sel of selections) {
  const stepId = String(sel.step ?? '').trim();
  if (!stepId) continue;

  const rawVal = String(sel.value ?? '').trim();
  const labelVal = findLabel(stepId, rawVal);

  // Por stepId y sus variantes
  addPlaceholder(stepId, labelVal, rawVal);

  // Por alias si aplica (+ sus variantes)
  const alias = aliasMap[String(stepId).toLowerCase()] || aliasMap[stepId];
  if (alias) addPlaceholder(alias, labelVal, rawVal);
}

