  const tu=reportParam.toLowerCase();
  if(!tu){ reportText='⚠️ Uso: /reporte_vendedor usuario'; }
  else { const rows=filterByMonth(logRows,currentYear,currentMonth).filter(r=>(r.vendedor_usuario||'').toLowerCase()===tu); let total=0; reportText=`📊 *DETALLE ${tu.toUpperCase()} - ${monthNames[currentMonth-1].toUpperCase()} ${currentYear}*\n\n`; rows.forEach((r,i)=>{ const st=r.estatus==='revisada'?`🔄 v${r.version}`:'✅'; reportText+=`${i+1}. *${r.folio}*\n   🏭 ${r.maquina} → ${r.cliente_nombre}\n   💰 $${money(r.precio_total)} USD | ${st}\n\n`; total+=Number(r.precio_total)||0; }); reportText+=`*Total:* ${rows.length} cotizaciones | $${money(total)} USD`; if(rows.length===0) reportText=`📊 Sin cotizaciones para ${tu}.`; }
}
else if (reportType === 'my_quotes') {
  const rows=filterByMonth(logRows,currentYear,currentMonth).filter(r=>(r.vendedor_usuario||'').toLowerCase()===usuario.toLowerCase()); let total=0;
  reportText=`📋 *TUS COTIZACIONES - ${monthNames[currentMonth-1].toUpperCase()} ${currentYear}*\n\n`;
  rows.forEach((r,i)=>{ const st=r.estatus==='revisada'?`🔄 v${r.version}`:'✅ Enviada'; reportText+=`${i+1}. *${r.folio}*\n   🏭 ${r.maquina} → ${r.cliente_nombre}\n   💰 $${money(r.precio_total)} USD | ${st}\n\n`; total+=Number(r.precio_total)||0; });
  reportText+=`*Total:* ${rows.length} cotizaciones | $${money(total)} USD`;
  if(rows.length===0) reportText='📋 No tienes cotizaciones este mes.';
}
else if (reportType === 'export_excel') {
  let year=currentYear, month=currentMonth;
  if(reportParam){ const p=reportParam.split('-'); year=parseInt(p[0])||currentYear; month=parseInt(p[1])||currentMonth; }
  const rows=filterByMonth(logRows,year,month);
  if(rows.length===0) return [{ json: { chatId, text: `📊 No hay datos para exportar en ${monthNames[month-1]} ${year}.`, reply_markup: {}, isExcel: false } }];
  const headers=['Folio','Fecha','Actualización','Vendedor','Nombre Vendedor','Cliente','Email Cliente','Máquina','Precio Base','Precio Total','Opciones','PDF URL','Estatus','Versión'];
  let csv=headers.join('\t')+'\n';
  rows.forEach(r=>{ csv+=[r.folio,r.fecha,r.fecha_actualizacion,r.vendedor_usuario,r.vendedor_nombre,r.cliente_nombre,r.cliente_email,r.maquina,r.precio_base,r.precio_total,(r.opciones_detalle||'').replace(/\t/g,' '),r.pdf_drive_url,r.estatus,r.version].join('\t')+'\n'; });
  const buf = Buffer.from(csv,'utf-8');
  const b64 = buf.toString('base64');
  const fn = `Reporte_${year}-${String(month).padStart(2,'0')}.csv`;
  return [{ json: { chatId, text: `📊 Exportando ${rows.length} cotizaciones de ${monthNames[month-1]} ${year}`, reply_markup: {}, isExcel: true, excelFileName: fn }, binary: { data: { data: b64, mimeType: 'text/csv', fileName: fn } } }];
}

return [{ json: { chatId, text: reportText || '⚠️ Comando no reconocido.', reply_markup: {}, isExcel: false } }];
